const SkillChip = ({ name, icon, delay, visible }: { name: string; icon: React.ReactNode; delay: number; visible: boolean }) => (
  <div
    className="flex flex-col items-center gap-2 group transition-all duration-500"
    style={{
      opacity: visible ? 1 : 0,
      transform: visible ? 'translateY(0) scale(1)' : 'translateY(20px) scale(0.9)',
      transitionDelay: `${delay}ms`,
    }}
  >
    <div className="skill-chip-icon rounded-xl p-3 border group-hover:scale-110 transition-all duration-200 shadow-sm"
      style={{ backgroundColor: 'var(--bg-card)', borderColor: 'var(--border-color)' }}>
      {icon}
    </div>
    <span className="skill-chip-label text-xs transition-colors font-medium" style={{ color: 'var(--text-muted)' }}>{name}</span>
  </div>
);

const Skills = () => {
  const { ref, visible } = useScrollReveal();

  return (
    <section
      id="skills"
      ref={ref as React.RefObject<HTMLElement>}
      className="py-24 px-6"
      style={{ backgroundColor: 'var(--bg-secondary)' }}
    >
      <div className="max-w-5xl mx-auto">
        <h2
          className="text-3xl font-bold mb-14 text-center transition-all duration-700"
          style={{ opacity: visible ? 1 : 0, transform: visible ? 'translateY(0)' : 'translateY(24px)', color: 'var(--text-primary)' }}
        >
          Technical <span className="text-indigo-400">Skills</span>
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {groups.map((group, gi) => (
            <div
              key={group.label}
              className={`rounded-2xl p-6 bg-gradient-to-br ${group.color} border ${group.border} backdrop-blur-sm transition-all duration-700`}
              style={{
                opacity: visible ? 1 : 0,
                transform: visible ? 'translateY(0)' : 'translateY(32px)',
                transitionDelay: `${gi * 100}ms`,
              }}
            >
              <p className="text-xs font-semibold uppercase tracking-widest mb-5" style={{ color: 'var(--text-muted)' }}>{group.label}</p>
              <div className="flex flex-wrap gap-6">
                {group.items.map((skill, si) => (
                  <SkillChip
                    key={skill.name}
                    name={skill.name}
                    icon={skill.icon}
                    delay={gi * 100 + si * 60}
                    visible={visible}
                  />
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Skills;
